import { useState } from 'react';

const AdminDashboard = () => {
  // 1. State para sa switching ng tabs (Members vs All Posts)
  const [activeTab, setActiveTab] = useState('posts');

  // 2. Sample data para sa Posts (Title, Author, Status)
  const [posts, setPosts] = useState([
    { id: 1, title: 'bsxjshbjcs', author: 'glaiza', status: 'PUBLISHED' },
    { id: 2, title: 'BlackPink', author: 'glaiza', status: 'PUBLISHED' },
  ]);

  // 3. Logic para sa Remove button
  const handleRemove = (id) => {
    if (window.confirm('Are you sure you want to remove this post?')) {
      setPosts(posts.filter(post => post.id !== id));
    }
  };

  return (
    <div style={{ padding: '40px', maxWidth: '1000px', margin: '0 auto' }}>
      <h1 style={{ textAlign: 'center', fontFamily: 'cursive', color: '#5e2a3d' }}>Admin Dashboard</h1>
      
      {/* Tab Selection */}
      <div style={{ display: 'flex', justifyContent: 'center', gap: '20px', marginBottom: '30px', borderBottom: '1px solid #ddd', paddingBottom: '10px' }}>
        <button 
          onClick={() => setActiveTab('members')}
          style={{ background: 'none', border: 'none', cursor: 'pointer', fontWeight: activeTab === 'members' ? 'bold' : 'normal' }}
        >
          Members (2)
        </button>
        <button 
          onClick={() => setActiveTab('posts')}
          style={{ 
            backgroundColor: activeTab === 'posts' ? '#ff69b4' : 'transparent', 
            color: activeTab === 'posts' ? 'white' : 'black',
            border: 'none', padding: '5px 20px', borderRadius: '20px', cursor: 'pointer' 
          }}
        >
          All Posts ({posts.length})
        </button>
      </div>

      {/* Table for Posts */}
      {activeTab === 'posts' && (
        <div style={{ backgroundColor: 'white', borderRadius: '15px', overflow: 'hidden', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ backgroundColor: '#ff1493', color: 'white' }}>
                <th style={{ padding: '15px', textAlign: 'left' }}>TITLE</th>
                <th style={{ padding: '15px', textAlign: 'left' }}>AUTHOR</th>
                <th style={{ padding: '15px', textAlign: 'left' }}>STATUS</th>
                <th style={{ padding: '15px', textAlign: 'center' }}>ACTION</th>
              </tr>
            </thead>
            <tbody>
              {posts.map((post) => (
                <tr key={post.id} style={{ borderBottom: '1px solid #eee' }}>
                  <td style={{ padding: '15px' }}>{post.title}</td>
                  <td style={{ padding: '15px' }}>{post.author}</td>
                  <td style={{ padding: '15px' }}>
                    <span style={{ 
                      backgroundColor: '#d4edda', color: '#155724', 
                      padding: '4px 12px', borderRadius: '15px', fontSize: '12px', fontWeight: 'bold' 
                    }}>
                      {post.status}
                    </span>
                  </td>
                  <td style={{ padding: '15px', textAlign: 'center' }}>
                    <button 
                      onClick={() => handleRemove(post.id)}
                      style={{ 
                        backgroundColor: '#ff4d4d', color: 'white', border: 'none', 
                        padding: '8px 20px', borderRadius: '20px', cursor: 'pointer' 
                      }}
                    >
                      Remove
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {activeTab === 'members' && (
        <div style={{ textAlign: 'center', padding: '20px' }}>
          <p>Members list will be displayed here.</p>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
